#include "llvm/Transforms/Instrumentation.h"
#include "llvm/IR/Function.h"
#include "llvm/IR/Instructions.h"
#include "llvm/IR/IRBuilder.h"
#include "llvm/Analysis/LoopInfo.h"
#include "llvm/ExecutionEngine/ParallelExecutor.h"
#include "llvm/Support/async.h"

using namespace llvm;

namespace {
struct InstrumentMemoryAccessPatternsPass : public FunctionPass {
  static char ID;
  InstrumentMemoryAccessPatternsPass() : FunctionPass(ID) {}

  bool runOnFunction(Function &F) override {
    LoopInfo &LI = getAnalysis<LoopInfo>();
    bool Changed = false;

    for (BasicBlock &BB : F) {
      for (Instruction &I : BB) {
        if (isa<LoadInst>(I) || isa<StoreInst>(I)) {
          Value *PtrOp = I.getOperand(0); // Pointer operand for load/store
          Loop *L = LI.getLoopFor(I.getParent());
          unsigned NestingDepth = 0;
          while (L) {
            ++NestingDepth;
            L = L->getParentLoop();
          }

          if (NestingDepth <= 2)
            continue; // Skip shallow loops

          IRBuilder<> Builder(&I);
          ConstantInt *XorMask = ConstantInt::get(Type::getInt64Ty(F.getContext()), 0xA5A5A5A5ULL);
          Value *TransformedAddr;

          if (NestingDepth > 4) {
            // Offload address transformation to background thread for deep nests
            auto TransformAddr = [PtrOp, XorMask]() -> Value* {
              return BinaryOperator::CreateXor(PtrOp, XorMask, "xor.addr");
            };
            TransformedAddr = ParallelExecutor::executeAsync(std::move(TransformAddr));
          } else {
            // Synchronous transformation for moderate nesting
            TransformedAddr = BinaryOperator::CreateXor(PtrOp, XorMask, "xor.addr", &I);
          }

          // Insert debugging intrinsic with transformed address
          Function *DebugIntrinsic = Intrinsic::getDeclaration(
              &F, Intrinsic::debugtrap, {});
          Builder.CreateCall(DebugIntrinsic, {TransformedAddr});
          Changed = true;
        }
      }
    }

    return Changed;
  }

  void getAnalysisUsage(AnalysisUsage &AU) const override {
    AU.addRequired<LoopInfo>();
    AU.setPreservesCFG();
  }
};
} // end anonymous namespace

char InstrumentMemoryAccessPatternsPass::ID = 0;
static RegisterPass<InstrumentMemoryAccessPatternsPass>
X("instrument-mem-access-patterns", "Instrument Memory Access Patterns Pass",
   false /* Only looks at CFG */,
   false /* Analysis Pass */);
```

